parameters.message:
={{ (() => {
  const b = $json.body;
  const name = b.full_name ? b.full_name : '';
  const greeting = name ? ('Bonjour ' + name + ',') : 'Bonjour,';
  const labels = { setup: 'Définir mon mot de passe', reset: 'Réinitialiser mon mot de passe' };
  const btnLabel = labels[b.kind];
  const hasBtn = b.link && btnLabel;
  const button = hasBtn
    ? ('<table role="presentation" cellpadding="0" cellspacing="0" style="margin:24px 0;"><tr><td style="border-radius:8px;background:#7d1c34;">'
       + '<a href="' + b.link + '" style="display:inline-block;padding:13px 26px;font-family:\'Segoe UI\',Arial,sans-serif;font-size:15px;font-weight:600;color:#ffffff;text-decoration:none;border-radius:8px;">'
       + btnLabel + '</a></td></tr></table>')
    : '';
  const fallback = hasBtn
    ? ('<p style="font-size:12px;color:#888;line-height:1.5;">Si le bouton ne fonctionne pas, copiez-collez ce lien dans votre navigateur :<br><a href="' + b.link + '" style="color:#7d1c34;">' + b.link + '</a></p>'
       + '<p style="font-size:12px;color:#888;">Ce lien est valable 1 heure.</p>')
    : '';
  return '<div style="background:#f4f4f5;padding:24px 0;font-family:\'Segoe UI\',Arial,sans-serif;">'
    + '<table role="presentation" width="100%" cellpadding="0" cellspacing="0"><tr><td align="center">'
    + '<table role="presentation" width="560" cellpadding="0" cellspacing="0" style="background:#ffffff;border-radius:14px;overflow:hidden;border:1px solid #ececec;">'
    + '<tr><td style="background:#7d1c34;padding:22px 32px;"><img src="https://raw.githubusercontent.com/fingec/fingec-assets/refs/heads/main/fing.png" width="95" alt="Fingec" style="display:block;"></td></tr>'
    + '<tr><td style="padding:32px;color:#333;font-size:14px;line-height:1.65;">'
    + '<p style="margin:0 0 14px;font-size:16px;color:#1a1a1a;">' + greeting + '</p>'
    + '<p style="margin:0 0 4px;">' + b.intro + '</p>'
    + button + fallback
    + '<p style="margin:18px 0 0;">Cordialement,</p>'
    + '<table style="margin-top:14px;border-top:1px solid #7d1c34;padding-top:12px;width:100%;"><tr><td>'
    + '<span style="font-size:17px;font-weight:900;color:#7d1c34;">Cabinet Fingec</span><br>'
    + '<span style="font-size:12px;color:#666;">12 rue Exemple, 67000 Strasbourg</span><br>'
    + '<span style="font-size:13px;color:#444;">Cabinet membre de l\'Ordre des Experts-Comptables d\'Alsace</span><br>'
    + '<span style="font-size:12px;color:#7d1c34;">contact@fingec.fr / www.fingec.fr</span>'
    + '</td></tr></table></td></tr>'
    + '<tr><td style="background:#faf7f8;padding:14px 32px;border-top:1px solid #eee;"><p style="margin:0;font-size:11px;color:#999;">Cet e-mail vous est adressé car un compte vous concernant a été modifié sur l\'espace Fingec. Si vous n\'êtes pas concerné, ignorez ce message.</p></td></tr>'
    + '</table></td></tr></table></div>';
})() }}
